from sentence_transformers import SentenceTransformer, util

class FAQMatcher:
    def __init__(self, faqs: dict):
        self.model = SentenceTransformer("all-MiniLM-L6-v2")
        self.questions = list(faqs.keys())
        self.answers = list(faqs.values())
        self.q_embeddings = self.model.encode(
            self.questions, normalize_embeddings=True,
            convert_to_tensor=True
        )

    def match(self, query: str, threshold=0.60):
        q_emb = self.model.encode(
            query, normalize_embeddings=True,
            convert_to_tensor=True
        )
        scores = util.cos_sim(q_emb, self.q_embeddings)[0]
        best_idx = scores.argmax().item()
        best_score = float(scores[best_idx])
        if best_score < threshold:
            return None
        return {
            "question": self.questions[best_idx],
            "answer": self.answers[best_idx],
            "confidence": best_score,
        }

faq = FAQMatcher({
    "How do I reset my password?": "Go to Settings > Security > Reset Password.",
    "What is your refund policy?": "Full refund within 30 days of purchase.",
})
result = faq.match("I forgot my login credentials")
print(result)
